from typing import List
from functools import lru_cache

class Solution:
    def minimumValueSum(self, nums: List[int], andValues: List[int]) -> int:
        n = len(nums)
        m = len(andValues)

        # Check if m > n
        if m > n:
            return -1

        # Precompute prefix ANDs for all subarrays ending at each index
        prefix_and = [set() for _ in range(n)]
        for i in range(n):
            current_and = nums[i]
            prefix_and[i].add(current_and)
            for j in range(i - 1, -1, -1):
                current_and &= nums[j]
                prefix_and[i].add(current_and)

        # DP[i][j]: minimum sum of the last elements of the first j subarrays using the first i elements of nums
        INF = float('inf')
        dp = [[INF] * (m + 1) for _ in range(n + 1)]
        dp[0][0] = 0  # Base case: 0 elements, 0 subarrays, sum is 0

        for i in range(1, n + 1):
            for j in range(1, m + 1):
                # Try all possible k < i to split the array into j subarrays
                for k in range(j - 1, i):
                    # Check if the AND of nums[k..i-1] matches andValues[j-1]
                    if andValues[j - 1] in prefix_and[i - 1]:
                        dp[i][j] = min(dp[i][j], dp[k][j - 1] + nums[i - 1])

        return dp[n][m] if dp[n][m] != INF else -1
